module top_module(
  input touch_in,
  output led_out
);reg touch_state = 0;
  wire _tap_touch_in = touch_in & {1{1'b1}};


  always @(touch_in) begin
    if (touch_in == 1) begin
      touch_state <= 1;
    end else begin
      touch_state <= 0;
    end
  end

  assign led_out = touch_state;

endmodule
